const HTML = "<!doctype html>\n<html lang=\"en\">\n<head>\n<meta charset=\"utf-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n<title>Insight — cookieless, self-hosted web analytics (open source)</title>\n<meta name=\"description\" content=\"Insight is an open-source, cookieless web analytics dashboard you host yourself. Real-time visitors, revenue attribution and AI crawler tracking, with no cookies and no cookie banner. A privacy-first Google Analytics alternative.\">\n<link rel=\"canonical\" href=\"https://insightsite.nicolaslecocq.com/\">\n<meta name=\"robots\" content=\"index, follow, max-image-preview:large\">\n<meta name=\"theme-color\" content=\"#ffa950\">\n<meta property=\"og:type\" content=\"website\">\n<meta property=\"og:url\" content=\"https://insightsite.nicolaslecocq.com/\">\n<meta property=\"og:title\" content=\"Insight — cookieless, self-hosted web analytics\">\n<meta property=\"og:description\" content=\"Open-source analytics you run on your own server. Real-time visitors, revenue and AI crawlers, with no cookies and no banner.\">\n<meta property=\"og:site_name\" content=\"Insight\">\n<meta property=\"og:image\" content=\"https://insightsite.nicolaslecocq.com/og.svg\">\n<meta name=\"twitter:card\" content=\"summary_large_image\">\n<meta name=\"twitter:title\" content=\"Insight — cookieless, self-hosted web analytics\">\n<meta name=\"twitter:description\" content=\"Open-source analytics you run on your own server. Real-time, cookieless, privacy-first.\">\n<meta name=\"twitter:image\" content=\"https://insightsite.nicolaslecocq.com/og.svg\">\n<link rel=\"icon\" href=\"data:image/svg+xml,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 32 32'%3E%3Crect width='32' height='32' rx='9' fill='%23ffa950'/%3E%3Crect x='8' y='20' width='4' height='5' rx='2' fill='%23fff' fill-opacity='.5'/%3E%3Crect x='14' y='12' width='4' height='13' rx='2' fill='%23fff' fill-opacity='.75'/%3E%3Crect x='20' y='7' width='4' height='18' rx='2' fill='%23fff'/%3E%3C/svg%3E\">\n<script type=\"application/ld+json\">\n{\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"SoftwareApplication\",\n  \"name\": \"Insight\",\n  \"applicationCategory\": \"BusinessApplication\",\n  \"applicationSubCategory\": \"Web analytics\",\n  \"operatingSystem\": \"Docker, Linux\",\n  \"description\": \"Open-source, cookieless, self-hosted web analytics. Real-time visitors, revenue attribution, funnels, retention and AI crawler tracking, with no cookies and no cookie banner.\",\n  \"url\": \"https://insightsite.nicolaslecocq.com/\",\n  \"downloadUrl\": \"https://github.com/DigiHold/insight\",\n  \"license\": \"https://opensource.org/licenses/MIT\",\n  \"isAccessibleForFree\": true,\n  \"offers\": { \"@type\": \"Offer\", \"price\": \"0\", \"priceCurrency\": \"USD\" },\n  \"author\": { \"@type\": \"Person\", \"name\": \"Nicolas Lecocq\", \"url\": \"https://nicolaslecocq.com\" },\n  \"featureList\": [\n    \"Cookieless tracker\", \"Real-time dashboard\", \"Live visitor world map\",\n    \"Revenue attribution with Stripe\", \"Funnels and retention cohorts\",\n    \"AI crawler tracking\", \"Google Analytics 4 and Search Console import\",\n    \"Read-only CLI\"\n  ]\n}\n</script>\n<script type=\"application/ld+json\">\n{\n  \"@context\": \"https://schema.org\",\n  \"@type\": \"FAQPage\",\n  \"mainEntity\": [\n    { \"@type\": \"Question\", \"name\": \"Is Insight really free?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"Yes. The code is open source under the MIT licence. You pay only for the small server you run it on.\" } },\n    { \"@type\": \"Question\", \"name\": \"Is Insight a Google Analytics alternative?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"It covers the numbers most people open Google Analytics for, and adds revenue, a live map and AI crawler tracking. You can also connect GA4 if you want the old history in the same place.\" } },\n    { \"@type\": \"Question\", \"name\": \"Does Insight use cookies?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"No. The tracker is cookieless and sets nothing on the visitor device, so you do not need a cookie banner.\" } },\n    { \"@type\": \"Question\", \"name\": \"What do I need to self-host Insight?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"Docker and a small server. One compose file brings up the app and the database over HTTPS.\" } },\n    { \"@type\": \"Question\", \"name\": \"Can Insight track AI crawlers?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"Yes. It records visits from ChatGPT, Claude, Perplexity, Googlebot and others, per page, so you can see what the AI answers are reading.\" } },\n    { \"@type\": \"Question\", \"name\": \"How is the dashboard secured?\", \"acceptedAnswer\": { \"@type\": \"Answer\", \"text\": \"Access needs your email, your password and a 2FA code. There is no public sign-up, so nobody can create an account on your instance.\" } }\n  ]\n}\n</script>\n<style>\n  :root{\n    --accent:#ffa950; --accent-deep:#f5991f; --ink:#18181b; --muted:#5b5b66;\n    --bg:#f5f5f7; --card:rgba(255,255,255,.72); --border:rgba(24,24,27,.09);\n    --glass-hi:rgba(255,255,255,.9);\n    --a1:rgba(255,169,80,.20); --a2:rgba(99,102,241,.14); --a3:rgba(45,212,191,.12);\n    --sans:'Bricolage Grotesque',ui-sans-serif,system-ui,-apple-system,'Segoe UI',Roboto,sans-serif;\n    --body:ui-sans-serif,system-ui,-apple-system,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;\n    --mono:ui-monospace,'SF Mono',Menlo,Consolas,monospace;\n  }\n  @media (prefers-color-scheme:dark){\n    :root{--ink:#ececf1;--muted:#a1a1ab;--bg:#08080c;--card:rgba(255,255,255,.055);\n      --border:rgba(255,255,255,.1);--glass-hi:rgba(255,255,255,.28);\n      --a1:rgba(255,158,60,.16);--a2:rgba(99,102,241,.14);--a3:rgba(45,212,191,.08);}\n  }\n  *{box-sizing:border-box}\n  html{scroll-behavior:smooth}\n  body{margin:0;background:var(--bg);color:var(--ink);font-family:var(--body);\n    line-height:1.6;-webkit-font-smoothing:antialiased;overflow-x:clip;min-height:100vh}\n  body::before{content:\"\";position:fixed;inset:0;z-index:-1;pointer-events:none;\n    background:\n      radial-gradient(46% 40% at 15% 6%,var(--a1),transparent 70%),\n      radial-gradient(40% 44% at 88% 10%,var(--a2),transparent 70%),\n      radial-gradient(52% 46% at 55% 98%,var(--a3),transparent 72%);}\n  h1,h2,h3{font-family:var(--sans);letter-spacing:-.02em;line-height:1.08;margin:0}\n  a{color:inherit;text-decoration:none}\n  .wrap{max-width:1120px;margin:0 auto;padding:0 24px}\n  .accent{color:var(--accent-deep)}\n  .card{background:var(--card);border:1px solid var(--border);border-radius:20px;\n    box-shadow:0 1px 2px rgba(24,24,27,.04),0 18px 40px -22px rgba(24,24,27,.22);\n    backdrop-filter:blur(12px)}\n  .btn{display:inline-flex;align-items:center;gap:.5rem;font-weight:650;font-size:.98rem;\n    padding:.72rem 1.25rem;border-radius:13px;transition:transform .15s,background .2s,border-color .2s;\n    border:1px solid transparent;cursor:pointer;white-space:nowrap}\n  .btn:active{transform:scale(.98)}\n  .btn-primary{background:var(--accent);color:#573310;box-shadow:0 1px 2px rgba(87,51,16,.2)}\n  .btn-primary:hover{background:var(--accent-deep)}\n  .btn-ghost{background:var(--card);border-color:var(--border);color:var(--ink)}\n  .btn-ghost:hover{border-color:rgba(255,169,80,.55)}\n\n  /* header */\n  header{position:sticky;top:0;z-index:50;backdrop-filter:blur(14px);\n    background:color-mix(in srgb,var(--bg) 72%,transparent);border-bottom:1px solid var(--border)}\n  .nav{display:flex;align-items:center;justify-content:space-between;height:66px;gap:1rem}\n  .logo{display:flex;align-items:center;gap:.6rem}\n  .logo-name{display:flex;flex-direction:column;line-height:1}\n  .logo-name b{font-family:var(--sans);font-size:1.12rem;letter-spacing:-.02em}\n  .logo-name span{margin-left:1.35rem;font-size:.72rem;font-style:italic;color:var(--muted);margin-top:2px}\n  .logo-name span a:hover{color:var(--accent-deep)}\n  .nav-links{display:flex;align-items:center;gap:1.6rem;font-size:.95rem;color:var(--muted)}\n  .nav-links a:hover{color:var(--ink)}\n  .nav-cta{display:flex;align-items:center;gap:.6rem}\n  @media(max-width:780px){.nav-links{display:none}.nav-cta .hide-sm{display:none}}\n\n  /* hero */\n  .hero{padding:88px 0 40px;text-align:center}\n  .eyebrow{display:inline-flex;align-items:center;gap:.5rem;font-size:.82rem;font-weight:600;\n    color:var(--accent-deep);background:rgba(255,169,80,.12);border:1px solid rgba(255,169,80,.3);\n    padding:.35rem .8rem;border-radius:999px;margin-bottom:1.4rem}\n  h1{font-size:clamp(2.4rem,6vw,4.1rem);font-weight:800;max-width:15ch;margin:0 auto}\n  .sub{font-size:clamp(1.05rem,2.2vw,1.28rem);color:var(--muted);max-width:60ch;margin:1.4rem auto 0}\n  .hero-cta{display:flex;gap:.8rem;justify-content:center;flex-wrap:wrap;margin-top:2rem}\n  .hero-note{font-size:.9rem;color:var(--muted);margin-top:1rem}\n\n  /* dashboard mockup */\n  .shot{margin:52px auto 0;max-width:960px;padding:14px}\n  .shot-inner{border-radius:16px;overflow:hidden;border:1px solid var(--border);background:var(--bg)}\n  .shot-bar{display:flex;gap:6px;padding:11px 14px;border-bottom:1px solid var(--border);align-items:center}\n  .shot-bar i{width:11px;height:11px;border-radius:50%;background:var(--border)}\n  .shot-grid{display:grid;grid-template-columns:230px 1fr;gap:14px;padding:16px}\n  @media(max-width:640px){.shot-grid{grid-template-columns:1fr}}\n  .kpi{border:1px solid var(--border);border-radius:14px;padding:16px;background:var(--card)}\n  .kpi .lab{font-size:.7rem;text-transform:uppercase;letter-spacing:.12em;color:var(--muted)}\n  .kpi .big{font-family:var(--sans);font-size:2.6rem;font-weight:800;margin-top:2px}\n  .kpi .chip{display:inline-block;font-size:.72rem;color:#0a7d3f;background:rgba(16,185,129,.14);\n    padding:.1rem .45rem;border-radius:999px;margin-left:.4rem;vertical-align:middle}\n  .kpi .row{display:flex;justify-content:space-between;font-size:.82rem;color:var(--muted);margin-top:12px}\n  .kpi .row b{color:var(--ink);font-weight:650}\n  .chart{border:1px solid var(--border);border-radius:14px;padding:14px;background:var(--card);min-height:210px}\n\n  /* strip */\n  .strip{display:flex;flex-wrap:wrap;gap:.7rem;justify-content:center;margin:40px 0 8px}\n  .pill{font-size:.86rem;color:var(--muted);border:1px solid var(--border);background:var(--card);\n    padding:.4rem .85rem;border-radius:999px}\n\n  section{padding:76px 0}\n  .sec-head{text-align:center;max-width:62ch;margin:0 auto 48px}\n  .sec-head h2{font-size:clamp(1.8rem,4vw,2.7rem);font-weight:800}\n  .sec-head p{color:var(--muted);font-size:1.08rem;margin-top:.9rem}\n\n  .grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}\n  @media(max-width:900px){.grid{grid-template-columns:repeat(2,1fr)}}\n  @media(max-width:560px){.grid{grid-template-columns:1fr}}\n  .feat{padding:22px}\n  .feat .ic{width:42px;height:42px;border-radius:11px;display:grid;place-items:center;\n    background:rgba(255,169,80,.14);color:var(--accent-deep);margin-bottom:14px}\n  .feat h3{font-size:1.08rem;font-weight:700}\n  .feat p{color:var(--muted);font-size:.95rem;margin:.5rem 0 0}\n\n  /* CLI */\n  .cli{display:grid;grid-template-columns:1fr 1.15fr;gap:34px;align-items:center}\n  @media(max-width:820px){.cli{grid-template-columns:1fr}}\n  .term{background:#0c0c12;border:1px solid rgba(255,255,255,.1);border-radius:16px;\n    font-family:var(--mono);font-size:.83rem;color:#d4d4dc;overflow:hidden;\n    box-shadow:0 24px 50px -24px rgba(0,0,0,.5)}\n  .term-bar{display:flex;gap:6px;padding:11px 14px;border-bottom:1px solid rgba(255,255,255,.08)}\n  .term-bar i{width:11px;height:11px;border-radius:50%;background:#3a3a44}\n  .term pre{margin:0;padding:16px 18px;white-space:pre-wrap;line-height:1.65}\n  .term .p{color:#ffa950}.term .g{color:#5fd39a}.term .d{color:#8a8a97}\n\n  /* steps */\n  .steps{display:grid;grid-template-columns:repeat(3,1fr);gap:16px}\n  @media(max-width:760px){.steps{grid-template-columns:1fr}}\n  .step{padding:22px}\n  .step .n{font-family:var(--sans);font-size:1.1rem;font-weight:800;width:34px;height:34px;\n    border-radius:10px;display:grid;place-items:center;background:var(--accent);color:#573310;margin-bottom:12px}\n  .step h3{font-size:1.05rem;font-weight:700}\n  .step p{color:var(--muted);font-size:.95rem;margin:.5rem 0 0}\n\n  /* faq */\n  .faq{max-width:760px;margin:0 auto}\n  details{border:1px solid var(--border);border-radius:14px;background:var(--card);margin-bottom:12px;padding:2px 20px}\n  summary{cursor:pointer;font-weight:650;padding:16px 0;list-style:none;display:flex;justify-content:space-between;gap:1rem}\n  summary::-webkit-details-marker{display:none}\n  summary::after{content:\"+\";color:var(--accent-deep);font-size:1.3rem;line-height:1}\n  details[open] summary::after{content:\"–\"}\n  details p{color:var(--muted);margin:0 0 18px}\n\n  /* final + footer */\n  .final{text-align:center;padding:30px}\n  .final h2{font-size:clamp(1.9rem,4.5vw,2.9rem);font-weight:800;max-width:18ch;margin:0 auto}\n  footer{border-top:1px solid var(--border);padding:44px 0 60px;margin-top:20px}\n  .foot{display:flex;justify-content:space-between;gap:24px;flex-wrap:wrap;align-items:flex-start}\n  .foot p{color:var(--muted);font-size:.9rem;max-width:42ch;margin:.8rem 0 0}\n  .foot-links{display:flex;gap:1.6rem;font-size:.92rem;color:var(--muted)}\n  .foot-links a:hover{color:var(--ink)}\n  .sig{font-style:italic}.sig a{color:var(--accent-deep);font-weight:600}\n</style>\n</head>\n<body>\n\n<header>\n  <div class=\"wrap nav\">\n    <a class=\"logo\" href=\"#top\" aria-label=\"Insight home\">\n      <svg width=\"32\" height=\"32\" viewBox=\"0 0 32 32\" aria-hidden=\"true\"><rect width=\"32\" height=\"32\" rx=\"9\" fill=\"#ffa950\"/><rect x=\"8\" y=\"20\" width=\"4\" height=\"5\" rx=\"2\" fill=\"#fff\" fill-opacity=\".5\"/><rect x=\"14\" y=\"12\" width=\"4\" height=\"13\" rx=\"2\" fill=\"#fff\" fill-opacity=\".75\"/><rect x=\"20\" y=\"7\" width=\"4\" height=\"18\" rx=\"2\" fill=\"#fff\"/></svg>\n      <span class=\"logo-name\"><b>Insight</b><span>by <a href=\"https://nicolaslecocq.com\" target=\"_blank\" rel=\"noopener\">Nicolas&nbsp;Lecocq</a></span></span>\n    </a>\n    <nav class=\"nav-links\">\n      <a href=\"#features\">Features</a>\n      <a href=\"#cli\">CLI</a>\n      <a href=\"#self-host\">Self-host</a>\n      <a href=\"#faq\">FAQ</a>\n    </nav>\n    <div class=\"nav-cta\">\n      <a class=\"btn btn-ghost hide-sm\" href=\"https://insight.nicolaslecocq.com\">Sign in</a>\n      <a class=\"btn btn-primary\" href=\"https://github.com/DigiHold/insight\" target=\"_blank\" rel=\"noopener\">\n        <svg width=\"17\" height=\"17\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M12 .5A11.5 11.5 0 0 0 .5 12a11.5 11.5 0 0 0 7.86 10.92c.58.1.79-.25.79-.56v-2c-3.2.7-3.88-1.54-3.88-1.54-.53-1.33-1.3-1.69-1.3-1.69-1.06-.72.08-.71.08-.71 1.17.08 1.79 1.2 1.79 1.2 1.04 1.79 2.73 1.27 3.4.97.1-.76.41-1.27.74-1.56-2.55-.29-5.23-1.28-5.23-5.68 0-1.25.45-2.28 1.19-3.08-.12-.29-.52-1.46.11-3.05 0 0 .97-.31 3.18 1.18a11 11 0 0 1 5.8 0c2.2-1.49 3.17-1.18 3.17-1.18.63 1.59.23 2.76.11 3.05.74.8 1.19 1.83 1.19 3.08 0 4.41-2.69 5.38-5.25 5.67.42.36.8 1.08.8 2.18v3.23c0 .31.21.67.8.56A11.5 11.5 0 0 0 23.5 12 11.5 11.5 0 0 0 12 .5Z\"/></svg>\n        Star on GitHub\n      </a>\n    </div>\n  </div>\n</header>\n\n<main id=\"top\">\n  <section class=\"hero\">\n    <div class=\"wrap\">\n      <span class=\"eyebrow\">Open source · self-hosted</span>\n      <h1>Cookieless web analytics you host yourself</h1>\n      <p class=\"sub\">Insight is a privacy-first analytics dashboard you run on your own server. Watch real-time visitors, revenue and AI crawlers, with no cookies and no cookie banner in anyone's way.</p>\n      <div class=\"hero-cta\">\n        <a class=\"btn btn-primary\" href=\"https://github.com/DigiHold/insight\" target=\"_blank\" rel=\"noopener\">Get it on GitHub</a>\n        <a class=\"btn btn-ghost\" href=\"#features\">See what it does</a>\n      </div>\n      <p class=\"hero-note\">Free and open source under the MIT licence. Your data stays on the machine you chose.</p>\n\n      <div class=\"shot card\">\n        <div class=\"shot-inner\">\n          <div class=\"shot-bar\"><i></i><i></i><i></i></div>\n          <div class=\"shot-grid\">\n            <div class=\"kpi\">\n              <div class=\"lab\">Last 30 days</div>\n              <div class=\"big\">48,290<span class=\"chip\">▲ 12%</span></div>\n              <div class=\"row\"><span>Pageviews</span><b>131,204</b></div>\n              <div class=\"row\"><span>Revenue</span><b>$9,140</b></div>\n              <div class=\"row\"><span>Bounce</span><b>38%</b></div>\n              <div class=\"row\"><span>Avg time</span><b>1m 46s</b></div>\n            </div>\n            <div class=\"chart\">\n              <svg viewBox=\"0 0 520 200\" width=\"100%\" height=\"100%\" preserveAspectRatio=\"none\" aria-hidden=\"true\">\n                <defs><linearGradient id=\"g\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\"><stop offset=\"0\" stop-color=\"#ffa950\" stop-opacity=\".35\"/><stop offset=\"1\" stop-color=\"#ffa950\" stop-opacity=\"0\"/></linearGradient></defs>\n                <path d=\"M0,150 C60,120 90,90 140,110 C190,130 210,60 270,70 C330,80 350,30 410,50 C460,66 490,40 520,44 L520,200 L0,200 Z\" fill=\"url(#g)\"/>\n                <path d=\"M0,150 C60,120 90,90 140,110 C190,130 210,60 270,70 C330,80 350,30 410,50 C460,66 490,40 520,44\" fill=\"none\" stroke=\"#f5991f\" stroke-width=\"3\"/>\n              </svg>\n            </div>\n          </div>\n        </div>\n      </div>\n\n      <div class=\"strip\">\n        <span class=\"pill\">No cookies</span>\n        <span class=\"pill\">Runs on your server</span>\n        <span class=\"pill\">Open source (MIT)</span>\n        <span class=\"pill\">Updates every 5 seconds</span>\n        <span class=\"pill\">GDPR-friendly</span>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"why\">\n    <div class=\"wrap sec-head\">\n      <h2>Own your analytics again</h2>\n      <p>Google Analytics samples your data, asks visitors to accept cookies, and keeps everything on Google's servers. Insight does the opposite. You install it once, drop one script tag on your sites, and every visit lands in a database you control. No third party reads it, and there is nothing to consent to because there are no cookies.</p>\n    </div>\n  </section>\n\n  <section id=\"features\" style=\"padding-top:0\">\n    <div class=\"wrap\">\n      <div class=\"sec-head\">\n        <h2>Everything on one screen</h2>\n        <p>The numbers people open an analytics tool for, plus the ones Google Analytics never showed you.</p>\n      </div>\n      <div class=\"grid\">\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 3v18h18\"/><path d=\"m7 14 3-4 4 3 5-7\"/></svg></div><h3>Real-time dashboard</h3><p>Visitors, pageviews, bounce rate and average time, refreshed every five seconds. The number moves while you watch it.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"9\"/><path d=\"M3 12h18M12 3a15 15 0 0 1 0 18M12 3a15 15 0 0 0 0 18\"/></svg></div><h3>Live world map</h3><p>A globe of who is on your site right now, with the city, the page and the referrer for each visitor.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 1v22M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6\"/></svg></div><h3>Revenue attribution</h3><p>Connect Stripe and see which channels and campaigns bring paying customers, with refunds counted against the day they happened.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M3 4h18l-7 8v6l-4 2v-8L3 4Z\"/></svg></div><h3>Funnels and retention</h3><p>Track drop-off across the steps that matter, and see how many visitors come back week after week.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"4\" y=\"4\" width=\"16\" height=\"16\" rx=\"3\"/><path d=\"M9 9h.01M15 9h.01M8 15h8\"/></svg></div><h3>AI crawler tracking</h3><p>See when ChatGPT, Claude, Perplexity and Google's AI bots read your pages, and which pages they read.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M21 12a9 9 0 1 1-9-9\"/><path d=\"M21 3v6h-6\"/></svg></div><h3>GA4 and Search Console</h3><p>Pull Google Analytics 4 and Search Console into the same dashboard when you want the old history or the search queries.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 2 4 6v6c0 5 3.5 8 8 10 4.5-2 8-5 8-10V6l-8-4Z\"/><path d=\"m9 12 2 2 4-4\"/></svg></div><h3>Cookieless tracker</h3><p>A small first-party script with no cookies and no fingerprinting. Nothing to disclose to visitors, nothing for a blocker to catch.</p></div>\n        <div class=\"feat card\"><div class=\"ic\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\" rx=\"1.5\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\" rx=\"1.5\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\" rx=\"1.5\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\" rx=\"1.5\"/></svg></div><h3>Make it yours</h3><p>Drag the cards to reorder your dashboard and hide the ones you never look at. It remembers your layout on each device.</p></div>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"cli\">\n    <div class=\"wrap cli\">\n      <div>\n        <h2 style=\"font-size:clamp(1.8rem,4vw,2.6rem);font-weight:800\">Ask your assistant for the numbers</h2>\n        <p style=\"color:var(--muted);font-size:1.08rem;margin-top:1rem\">Insight ships a read-only command line. Point Claude or a terminal at it and ask in plain words, for example \"how many visitors last month and the top pages\".</p>\n        <p style=\"color:var(--muted);font-size:1.08rem;margin-top:1rem\">The token can only read. It never unlocks the dashboard, which still needs your password and a 2FA code.</p>\n      </div>\n      <div class=\"term\">\n        <div class=\"term-bar\"><i></i><i></i><i></i></div>\n        <pre><span class=\"p\">$</span> insight stats 30d\n\nInsight — all sites — last 30 days\n\nVisitors: 48,290   Pageviews: 131,204   Bounce: 38%\nAvg time: 1m 46s   Revenue: $9,140 (214 sales)\n\n<span class=\"d\">Top pages</span>\n  /pricing          9,102  <span class=\"g\">████████</span>\n  /                 7,540  <span class=\"g\">██████</span>\n  /blog/launch      4,318  <span class=\"g\">███</span>\n\n<span class=\"d\">Top countries</span>\n  United States    18,204  <span class=\"g\">████████</span>\n  France            6,077  <span class=\"g\">██</span>\n  Germany           3,910  <span class=\"g\">█</span></pre>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"self-host\" style=\"padding-top:0\">\n    <div class=\"wrap\">\n      <div class=\"sec-head\">\n        <h2>Run it in a few minutes</h2>\n        <p>One server, one compose file, one script tag. After that the data is yours.</p>\n      </div>\n      <div class=\"steps\">\n        <div class=\"step card\"><div class=\"n\">1</div><h3>Set three values</h3><p>Copy the compose file and set your admin email, your password and a random secret.</p></div>\n        <div class=\"step card\"><div class=\"n\">2</div><h3>Start the container</h3><p>It brings its own database and serves the dashboard over HTTPS behind Cloudflare or Caddy.</p></div>\n        <div class=\"step card\"><div class=\"n\">3</div><h3>Add one script</h3><p>Paste a single script tag on each site you want to measure, and visits start showing up live.</p></div>\n      </div>\n    </div>\n  </section>\n\n  <section id=\"privacy\">\n    <div class=\"wrap sec-head\">\n      <h2>Private by default</h2>\n      <p>There are no cookies, so you skip the banner and stay clear of the consent rules that apply to Google Analytics. Visitor ids are first-party and built without fingerprinting. The data never leaves the server you chose, in the country you chose.</p>\n    </div>\n  </section>\n\n  <section id=\"faq\" style=\"padding-top:0\">\n    <div class=\"wrap\">\n      <div class=\"sec-head\"><h2>Questions</h2></div>\n      <div class=\"faq\">\n        <details open><summary>Is Insight really free?</summary><p>Yes. The code is open source under the MIT licence. You pay only for the small server you run it on.</p></details>\n        <details><summary>Is it a Google Analytics alternative?</summary><p>It covers the numbers most people open Google Analytics for, and adds revenue, a live map and AI crawler tracking. You can also connect GA4 if you want the old history in the same place.</p></details>\n        <details><summary>Does it use cookies?</summary><p>No. The tracker is cookieless and sets nothing on the visitor device, so you do not need a cookie banner.</p></details>\n        <details><summary>What do I need to self-host it?</summary><p>Docker and a small server. One compose file brings up the app and the database over HTTPS.</p></details>\n        <details><summary>Can it track AI crawlers?</summary><p>Yes. It records visits from ChatGPT, Claude, Perplexity, Googlebot and others, per page, so you can see what the AI answers are reading.</p></details>\n        <details><summary>How is the dashboard secured?</summary><p>Access needs your email, your password and a 2FA code. There is no public sign-up, so nobody can create an account on your instance.</p></details>\n      </div>\n    </div>\n  </section>\n\n  <section>\n    <div class=\"wrap\">\n      <div class=\"final card\">\n        <h2>Put it on your own server today</h2>\n        <p class=\"sub\" style=\"margin:1.1rem auto 0\">Clone the repository, follow the setup guide and own your web analytics.</p>\n        <div class=\"hero-cta\">\n          <a class=\"btn btn-primary\" href=\"https://github.com/DigiHold/insight\" target=\"_blank\" rel=\"noopener\">Get it on GitHub</a>\n          <a class=\"btn btn-ghost\" href=\"https://github.com/DigiHold/insight/blob/main/docs/setup.md\" target=\"_blank\" rel=\"noopener\">Read the setup guide</a>\n        </div>\n      </div>\n    </div>\n  </section>\n</main>\n\n<footer>\n  <div class=\"wrap foot\">\n    <div>\n      <a class=\"logo\" href=\"#top\">\n        <svg width=\"30\" height=\"30\" viewBox=\"0 0 32 32\" aria-hidden=\"true\"><rect width=\"32\" height=\"32\" rx=\"9\" fill=\"#ffa950\"/><rect x=\"8\" y=\"20\" width=\"4\" height=\"5\" rx=\"2\" fill=\"#fff\" fill-opacity=\".5\"/><rect x=\"14\" y=\"12\" width=\"4\" height=\"13\" rx=\"2\" fill=\"#fff\" fill-opacity=\".75\"/><rect x=\"20\" y=\"7\" width=\"4\" height=\"18\" rx=\"2\" fill=\"#fff\"/></svg>\n        <span class=\"logo-name\"><b>Insight</b></span>\n      </a>\n      <p>Open-source, cookieless, self-hosted web analytics. A privacy-first Google Analytics alternative you run yourself.</p>\n      <p class=\"sig\">by <a href=\"https://nicolaslecocq.com\" target=\"_blank\" rel=\"noopener\">Nicolas&nbsp;Lecocq</a></p>\n    </div>\n    <div class=\"foot-links\">\n      <a href=\"#features\">Features</a>\n      <a href=\"#cli\">CLI</a>\n      <a href=\"#self-host\">Self-host</a>\n      <a href=\"https://github.com/DigiHold/insight\" target=\"_blank\" rel=\"noopener\">GitHub</a>\n      <a href=\"https://insight.nicolaslecocq.com\">Sign in</a>\n    </div>\n  </div>\n</footer>\n\n</body>\n</html>\n";
const ROBOTS = "User-agent: *\nAllow: /\n\nSitemap: https://insightsite.nicolaslecocq.com/sitemap.xml\n";
const SITEMAP = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\n  <url><loc>https://insightsite.nicolaslecocq.com/</loc><changefreq>weekly</changefreq><priority>1.0</priority></url>\n</urlset>\n";
const LLMS = "# Insight\n\nInsight is an open-source, cookieless, self-hosted web analytics dashboard. It is a privacy-first alternative to Google Analytics that you run on your own server.\n\n## What it does\n- Real-time visitor dashboard, refreshed every 5 seconds\n- Live world map of current visitors with city, page and referrer\n- Revenue attribution via Stripe, including refunds\n- Funnels and weekly retention cohorts\n- AI crawler tracking (ChatGPT, Claude, Perplexity, Googlebot and others), per page\n- Optional Google Analytics 4 and Search Console import\n- Cookieless first-party tracker, no cookie banner needed\n- Read-only CLI to query the stats from a terminal or an AI assistant\n\n## Facts\n- Licence: MIT, free to use\n- Self-hosted with Docker on your own server\n- No cookies, no fingerprinting, GDPR-friendly\n- Source code: https://github.com/DigiHold/insight\n- Author: Nicolas Lecocq (https://nicolaslecocq.com)\n";
const OG = "<svg xmlns=\"http://www.w3.org/2000/svg\" width=\"1200\" height=\"630\" viewBox=\"0 0 1200 630\"><rect width=\"1200\" height=\"630\" fill=\"#0b0b12\"/><circle cx=\"180\" cy=\"120\" r=\"380\" fill=\"#ffa950\" fill-opacity=\"0.12\"/><circle cx=\"1050\" cy=\"560\" r=\"320\" fill=\"#6366f1\" fill-opacity=\"0.12\"/><g transform=\"translate(90,235)\"><rect width=\"120\" height=\"120\" rx=\"30\" fill=\"#ffa950\"/><rect x=\"30\" y=\"74\" width=\"15\" height=\"20\" rx=\"7\" fill=\"#fff\" fill-opacity=\"0.5\"/><rect x=\"52\" y=\"44\" width=\"15\" height=\"50\" rx=\"7\" fill=\"#fff\" fill-opacity=\"0.75\"/><rect x=\"75\" y=\"26\" width=\"15\" height=\"68\" rx=\"7\" fill=\"#fff\"/></g><text x=\"240\" y=\"300\" font-family=\"system-ui,sans-serif\" font-size=\"76\" font-weight=\"800\" fill=\"#fff\">Insight</text><text x=\"92\" y=\"430\" font-family=\"system-ui,sans-serif\" font-size=\"40\" font-weight=\"600\" fill=\"#c7c7d1\">Cookieless, self-hosted web analytics</text><text x=\"92\" y=\"490\" font-family=\"system-ui,sans-serif\" font-size=\"30\" fill=\"#8a8a97\">Open source · real-time · privacy-first · you own the data</text></svg>";
const resp = (body, type, secs) => new Response(body, { headers: { 'content-type': type, 'cache-control': 'public, max-age=' + secs } });
export default {
  fetch(request) {
    const { pathname } = new URL(request.url);
    if (pathname === '/robots.txt')  return resp(ROBOTS, 'text/plain; charset=utf-8', 86400);
    if (pathname === '/sitemap.xml') return resp(SITEMAP, 'application/xml; charset=utf-8', 86400);
    if (pathname === '/llms.txt')    return resp(LLMS, 'text/plain; charset=utf-8', 86400);
    if (pathname === '/og.svg')      return resp(OG, 'image/svg+xml; charset=utf-8', 604800);
    return resp(HTML, 'text/html; charset=utf-8', 3600);
  }
};
